var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"촉수를 끊어!","JPN":"触手を切れ！","ENG":"Sever the tentacles!","TWN":"砍掉所有觸手！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"키이라가 본체로 돌격할 수 있는 길을 뚫어라!","JPN":"キーラが本体に突撃できるように道を切り開け！","ENG":"Clear a path so Kiera can charge the main body!","TWN":"替琪伊拉殺向本體開路！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 뻔하지 않은 대답이니까, 마음에 들었거든.","JPN":"キャハハッ！　普通じゃない答えだから、気に入ったんだよ。","ENG":"Kyahaha! It wasn't a boring answer, so I liked it.","TWN":"哈哈哈！回答不落俗套，我喜歡。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"언젠가는 너도, 그런 대답을 할 수 있을 날이 올 거야.","JPN":"いつかはお前にも、そういう風に答えられる日が来るさ。","ENG":"Someday, you'll be able to give an answer like that too.","TWN":"總有一天，妳也能回答出這種答案。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그날을 기대하도록 하지!","JPN":"その日を期待するとしよう！","ENG":"Look forward to that day!","TWN":"讓我們期待那一天！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"후후, 그리고 키이라 씨를 보다 보면 그때 봤던 부함장님이 생각나요.","JPN":"ふふ、それにキーラさんを見ていると、あの時お会いした副艦長が思い出されるわ。","ENG":"Fufu... And when I look at Kiera, she reminds me of the first mate I met back then.","TWN":"呵呵，每次看著妳，都會讓我想起那時看到的副船長。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그분도 당신과 비슷하지만 다른 말씀을 하셨거든요.","JPN":"あの方も、あなたの言葉と近いけれど、少し違うことをおっしゃっていました。","ENG":"She said something a little like what you said but in her own way.","TWN":"她也說過一句有點類似但又不太一樣的話。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 것이 있는 법이라고.","JPN":"人の命や自分の自由を放棄してでも、守らなければいけないものはあるんだって。","ENG":"That there are things worth protecting even if it costs your freedom... even if it costs your life.","TWN":"人有時候會為了某些東西，付出自己的生命與自由去守護。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然囉。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"피로 뒤범벅된 제 모습마저 포용해 주신 주인님이 계신 것처럼요.","JPN":"血まみれの私の姿でさえ包み込んでくださった、ご主人様のような方がきっと。","ENG":"Just as my master embraced even the blood-soaked version of me.","TWN":"就像主人包容滿身鮮血的我一樣。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금 당장 떠올리지 않아도 괜찮아.","JPN":"今すぐ思い出さなくていい。","ENG":"It's okay if you can't think of them right now.","TWN":"現在馬上想不起來也沒關係。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내가 마시멜로를 나눠준 사람을 지키기 위해 싸우듯.","JPN":"オルカがマシュマロをくれた人を守るために戦うように。","ENG":"Just as I fight to protect the ones who shared theirs with me...","TWN":"就像我為了守護給我棉花糖的人而戰一樣，"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"언젠가 키이라도 그런 사람들을 지키기 위해 싸우면 되니까.","JPN":"キーラもいつか、そんな人のために戦えばいいから。","ENG":"One day, you can fight to protect the people who shared theirs with you.","TWN":"總有一天，妳也會為了守護那些人而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"벨라미, 내 딸이 다 커서 날 이해하게 되면 전해줘.","JPN":"ベラミー、娘が成長して私のことを理解できるようになったら伝えて。","ENG":"Bellamy. When my daughter grows up enough to understand, tell her this.","TWN":"貝拉米，等我女兒長大能理解我後告訴她，"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"엄마가… 많이 미안하다고 말이야.","JPN":"本当にごめんね……って。","ENG":"Tell her mother... is so, so sorry.","TWN":"媽媽……真的很抱歉。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"전원! 조금만 더 참고 버텨라!","JPN":"みんな！　もう少し耐えるんだ！","ENG":"Everyone! Hold on just a little longer!","TWN":"全員注意！再撐一下！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리의 공인 카운터가 마지막 일격을 준비하고 있다!","JPN":"我らの公認カウンターが最後の一撃を構えている！","ENG":"Our Official Counter is preparing the final blow!","TWN":"我們的公認制裁者正在準備最後一擊！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후훗, 제법 좋은 얼굴을 하고 있구나, 키이라.","JPN":"ふふっ。いい顔してるじゃない、キーラ。","ENG":"Fufu, you're wearing quite a nice expression now, Kiera.","TWN":"呵，琪伊拉，妳那表情不錯啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사람들에게 내일을 꿈꾸게 할 준비는 되었니?","JPN":"人々に明日を夢見させる準備はできたかしら？","ENG":"Are you ready to help people dream of tomorrow?","TWN":"準備好讓大家重新做夢了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"言うまでもなく。","ENG":"Of course.","TWN":"那是當然。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"대해적이 될 사람이라면, 이 정도는 가뿐히 해내야 하지 않겠어?","JPN":"大海賊になる人間なら、こんなの朝飯前さ。","ENG":"If I'm going to be a great pirate, something like this should be a breeze, don't you think?","TWN":"想成為大海盜的人，就得做到這樣不是嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"다들 물러나!","JPN":"みんな下がってろ！","ENG":"Everyone, get back!","TWN":"大家退後！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"해일에 휩쓸려 나가도 책임 안 질 테니까!","JPN":"津波に流されても責任取らねえからな！","ENG":"If you get swept away by a tidal wave, it's not my responsibility!","TWN":"要是被海嘯捲走，我可不負責！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"L5_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"L5_1","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};